$ErrorActionPreference = "Stop"
$Host.UI.RawUI.WindowTitle = "GY-NEXUS 한국형 쇼츠 스튜디오 V2 수정"

$scriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$projectCandidates = @(
    $scriptDir,
    (Split-Path -Parent $scriptDir),
    (Get-Location).Path
) | Select-Object -Unique

$projectRoot = $null
foreach ($candidate in $projectCandidates) {
    if ($candidate -and (Test-Path (Join-Path $candidate "package.json"))) {
        $projectRoot = (Resolve-Path $candidate).Path
        break
    }
}

if (-not $projectRoot) {
    Write-Host ""
    Write-Host "오류: GY-NEXUS 프로젝트 폴더를 찾지 못했습니다." -ForegroundColor Red
    Write-Host "압축을 푼 폴더를 GY-NEXUS 프로젝트 안에 넣고 다시 실행하세요." -ForegroundColor Yellow
    exit 1
}

Set-Location $projectRoot
$stamp = Get-Date -Format "yyyyMMdd-HHmmss"
$backupRoot = Join-Path $projectRoot ".gy-backups\korean-shorts-v2-fix-$stamp"
$logFile = Join-Path $projectRoot "korean-shorts-v2-build-$stamp.log"

$writeFiles = [ordered]@{
    "app\admin\korean-shorts\page.tsx" = ""
    "components\korean-shorts\KoreanShortsStudio.tsx" = ""
    "components\korean-shorts\KoreanShortsStudio.module.css" = ""
    "components\admin\AdminSidebar.tsx" = ""
    "components\admin\AdminMobileDock.tsx" = ""
}

$deleteFiles = @(
    "app\api\korean-shorts\generate\route.ts"
    "lib\korean-shorts\types.ts"
    "lib\korean-shorts\fallback.ts"
)

$records = New-Object System.Collections.Generic.List[object]

function Backup-Target([string]$relative) {
    $target = Join-Path $projectRoot $relative
    $existed = Test-Path $target
    $backup = Join-Path $backupRoot $relative

    if ($existed) {
        New-Item -ItemType Directory -Force -Path (Split-Path -Parent $backup) | Out-Null
        Copy-Item $target $backup -Force
    }

    $records.Add([pscustomobject]@{
        Relative = $relative
        Target = $target
        Backup = $backup
        Existed = $existed
    }) | Out-Null
}

function Restore-All {
    for ($index = $records.Count - 1; $index -ge 0; $index--) {
        $record = $records[$index]
        if ($record.Existed -and (Test-Path $record.Backup)) {
            New-Item -ItemType Directory -Force -Path (Split-Path -Parent $record.Target) | Out-Null
            Copy-Item $record.Backup $record.Target -Force
        }
        elseif (Test-Path $record.Target) {
            Remove-Item $record.Target -Force -ErrorAction SilentlyContinue
        }
    }
}

Write-Host ""
Write-Host "==========================================================" -ForegroundColor DarkCyan
Write-Host " GY-NEXUS 한국형 쇼츠 스튜디오 V2 수정본" -ForegroundColor Cyan
Write-Host "==========================================================" -ForegroundColor DarkCyan
Write-Host "프로젝트: $projectRoot" -ForegroundColor White
Write-Host ""
Write-Host "이전 V1의 불안정한 Gemini API·영상 업로드 코드를 제거합니다." -ForegroundColor Yellow
Write-Host "기존 Content Factory를 사용해 대본·장면·SRT를 확실하게 생성합니다." -ForegroundColor Green
Write-Host "Gemini·CapCut·AlphaCut은 한 화면에서 복사·다운로드·열기로 연결합니다." -ForegroundColor Green
Write-Host ""

try {
    $oldPatch = Join-Path $projectRoot "PATCH"
    if (Test-Path $oldPatch) {
        Remove-Item -Recurse -Force $oldPatch
        Write-Host "정리: 이전 임시 PATCH 폴더 삭제" -ForegroundColor Yellow
    }

    foreach ($entry in $writeFiles.GetEnumerator()) {
        $relative = [string]$entry.Key
        Backup-Target $relative
        $target = Join-Path $projectRoot $relative
        New-Item -ItemType Directory -Force -Path (Split-Path -Parent $target) | Out-Null
        [System.IO.File]::WriteAllBytes(
            $target,
            [System.Convert]::FromBase64String([string]$entry.Value)
        )
        Write-Host "적용: $relative" -ForegroundColor Green
    }

    foreach ($relative in $deleteFiles) {
        $target = Join-Path $projectRoot $relative
        if (Test-Path $target) {
            Backup-Target $relative
            Remove-Item $target -Force
            Write-Host "제거: $relative" -ForegroundColor Yellow
        }
    }

    $gitignore = Join-Path $projectRoot ".gitignore"
    Backup-Target ".gitignore"
    if (-not (Test-Path $gitignore)) {
        New-Item -ItemType File -Force -Path $gitignore | Out-Null
    }
    $ignoreLines = @(
        ".gy-backups/",
        "PATCH/",
        "korean-shorts-v2-build-*.log",
        "$(Split-Path -Leaf $scriptDir)/"
    )
    $currentIgnore = Get-Content $gitignore -ErrorAction SilentlyContinue
    foreach ($line in $ignoreLines) {
        if ($currentIgnore -notcontains $line) {
            Add-Content -Path $gitignore -Value $line -Encoding utf8
            $currentIgnore += $line
        }
    }

    $nextFolder = Join-Path $projectRoot ".next"
    if (Test-Path $nextFolder) {
        Remove-Item -Recurse -Force $nextFolder -ErrorAction SilentlyContinue
    }

    Write-Host ""
    Write-Host "프로덕션 빌드를 검증합니다..." -ForegroundColor Cyan
    Write-Host "빌드 로그: $logFile" -ForegroundColor DarkGray
    Write-Host ""

    & npm.cmd run build 2>&1 | Tee-Object -FilePath $logFile
    $buildCode = $LASTEXITCODE

    if ($buildCode -ne 0) {
        throw "npm run build 실패 (종료 코드 $buildCode). 로그: $logFile"
    }

    Write-Host ""
    Write-Host "==========================================================" -ForegroundColor DarkGreen
    Write-Host " 적용 및 빌드 성공" -ForegroundColor Green
    Write-Host "==========================================================" -ForegroundColor DarkGreen
    Write-Host ""
    Write-Host "새 메뉴: /admin/korean-shorts" -ForegroundColor White
    Write-Host "중국 전용 메뉴: /admin/revenue-shorts" -ForegroundColor White
    Write-Host ""
    Write-Host "GitHub Desktop에서 변경사항을 Commit 후 Push하세요." -ForegroundColor Cyan
    Write-Host "추천 커밋: Fix Korean Shorts Studio integration" -ForegroundColor White
    Write-Host ""
    & git status --short
    exit 0
}
catch {
    $reason = $_.Exception.Message
    Write-Host ""
    Write-Host "적용 또는 빌드 실패: $reason" -ForegroundColor Red
    Write-Host "이번 수정 내용을 자동으로 원상 복구합니다." -ForegroundColor Yellow
    Restore-All
    Write-Host "원상 복구 완료" -ForegroundColor Green
    Write-Host "백업: $backupRoot" -ForegroundColor White
    Write-Host "로그: $logFile" -ForegroundColor White
    exit 1
}
